### 3. REACT CONTEXT USAGE IN COMPOUND COMPONENTS

**Example: Carousel Component**
Path: `/apps/v4/registry/new-york-v4/ui/carousel.tsx` (242 lines)

Pattern for context-based compound components:

```tsx
"use client"
import * as React from "react"

// 1. Define context type
type CarouselContextProps = {
  carouselRef: ReturnType<typeof useEmblaCarousel>[0]
  api: ReturnType<typeof useEmblaCarousel>[1]
  scrollPrev: () => void
  scrollNext: () => void
  canScrollPrev: boolean
  canScrollNext: boolean
} & CarouselProps

// 2. Create context
const CarouselContext = React.createContext<CarouselContextProps | null>(null)

// 3. Create custom hook for consumers
function useCarousel() {
  const context = React.useContext(CarouselContext)
  if (!context) {
    throw new Error("useCarousel must be used within a <Carousel />")
  }
  return context
}

// 4. Root component provides context
function Carousel({ orientation = "horizontal", opts, setApi, plugins, className, children, ...props }: React.ComponentProps<"div"> & CarouselProps) {
  const [carouselRef, api] = useEmblaCarousel({ ...opts, axis: orientation === "horizontal" ? "x" : "y" }, plugins)
  const [canScrollPrev, setCanScrollPrev] = React.useState(false)
  const [canScrollNext, setCanScrollNext] = React.useState(false)

  return (
    <CarouselContext.Provider value={{ carouselRef, api, opts, orientation, scrollPrev, scrollNext, canScrollPrev, canScrollNext }}>
      <div data-slot="carousel" {...props}>
        {children}
      </div>
    </CarouselContext.Provider>
  )
}

// 5. Sub-components consume context
function CarouselContent({ className, ...props }: React.ComponentProps<"div">) {
  const { carouselRef, orientation } = useCarousel()
  return <div ref={carouselRef} className="overflow-hidden" data-slot="carousel-content">...</div>
}

function CarouselItem({ className, ...props }: React.ComponentProps<"div">) {
  const { orientation } = useCarousel()
  return <div role="group" data-slot="carousel-item" className={cn(...)} {...props} />
}

export { useCarousel, Carousel, CarouselContent, CarouselItem, CarouselPrevious, CarouselNext }
```

