"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

type StepperContextProps = {
  activeStep: number
  setActiveStep: (step: number) => void
  orientation: "horizontal" | "vertical"
  totalSteps: number
}

const StepperContext = React.createContext<StepperContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)

  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }

  return context
}

type StepperItemContextProps = {
  step: number
  isActive: boolean
  isCompleted: boolean
  isDisabled: boolean
}

const StepperItemContext = React.createContext<StepperItemContextProps | null>(
  null
)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)

  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }

  return context
}

function Stepper({
  activeStep = 0,
  onStepChange,
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  activeStep?: number
  onStepChange?: (step: number) => void
  orientation?: "horizontal" | "vertical"
}) {
  const [internalStep, setInternalStep] = React.useState(activeStep)

  const currentStep = onStepChange ? activeStep : internalStep

  const setActiveStepFn = React.useCallback(
    (step: number) => {
      if (onStepChange) {
        onStepChange(step)
      } else {
        setInternalStep(step)
      }
    },
    [onStepChange]
  )

  React.useEffect(() => {
    if (!onStepChange) {
      setInternalStep(activeStep)
    }
  }, [activeStep, onStepChange])

  const totalSteps = React.Children.toArray(children).filter(
    (child) => React.isValidElement(child) && child.type === StepperItem
  ).length

  return (
    <StepperContext.Provider
      value={{
        activeStep: currentStep,
        setActiveStep: setActiveStepFn,
        orientation,
        totalSteps,
      }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "group/stepper flex",
          orientation === "horizontal"
            ? "flex-row items-start gap-2"
            : "flex-col gap-2",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

function StepperItem({
  step,
  className,
  children,
  disabled = false,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
  disabled?: boolean
}) {
  const { activeStep } = useStepper()

  const isActive = activeStep === step
  const isCompleted = activeStep > step
  const isDisabled = disabled

  return (
    <StepperItemContext.Provider
      value={{ step, isActive, isCompleted, isDisabled }}
    >
      <div
        data-slot="stepper-item"
        data-state={isActive ? "active" : isCompleted ? "completed" : "inactive"}
        className={cn(
          "group/stepper-item flex items-center gap-2",
          "data-[state=completed]:text-foreground data-[state=active]:text-foreground data-[state=inactive]:text-muted-foreground",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

function StepperTrigger({
  className,
  children,
  asChild = false,
  ...props
}: React.ComponentProps<"button"> & {
  asChild?: boolean
}) {
  const { setActiveStep } = useStepper()
  const { step, isActive, isCompleted, isDisabled } = useStepperItem()

  return (
    <button
      data-slot="stepper-trigger"
      data-state={isActive ? "active" : isCompleted ? "completed" : "inactive"}
      className={cn(
        "inline-flex items-center gap-3 rounded-md text-sm font-medium transition-colors focus-visible:ring-[3px] focus-visible:ring-ring/50 focus-visible:outline-1 focus-visible:outline-ring disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      disabled={isDisabled}
      onClick={() => setActiveStep(step)}
      {...props}
    >
      {children ?? (
        <StepperIndicator />
      )}
    </button>
  )
}

function StepperIndicator({
  className,
  children,
  ...props
}: React.ComponentProps<"span">) {
  const { step, isActive, isCompleted } = useStepperItem()

  return (
    <span
      data-slot="stepper-indicator"
      data-state={isActive ? "active" : isCompleted ? "completed" : "inactive"}
      className={cn(
        "inline-flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-semibold transition-colors",
        isCompleted &&
          "border-primary bg-primary text-primary-foreground",
        isActive &&
          "border-primary bg-background text-primary",
        !isActive &&
          !isCompleted &&
          "border-muted-foreground/40 bg-background text-muted-foreground",
        className
      )}
      {...props}
    >
      {children ?? (isCompleted ? (
        <svg
          xmlns="http://www.w3.org/2000/svg"
          width="16"
          height="16"
          viewBox="0 0 24 24"
          fill="none"
          stroke="currentColor"
          strokeWidth="2.5"
          strokeLinecap="round"
          strokeLinejoin="round"
        >
          <polyline points="20 6 9 17 4 12" />
        </svg>
      ) : (
        step + 1
      ))}
    </span>
  )
}

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"h4">) {
  return (
    <h4
      data-slot="stepper-title"
      className={cn("text-sm font-semibold leading-none", className)}
      {...props}
    />
  )
}

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn(
        "text-sm text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      role="separator"
      data-slot="stepper-separator"
      data-orientation={orientation}
      className={cn(
        "bg-muted-foreground/40 transition-colors group-data-[state=completed]/stepper-item:bg-primary",
        orientation === "horizontal"
          ? "h-0.5 w-full flex-1"
          : "ml-4 h-full min-h-4 w-0.5",
        className
      )}
      {...props}
    />
  )
}

function StepperContent({
  className,
  children,
  ...props
}: React.ComponentProps<"div">) {
  const { activeStep } = useStepper()
  const { step, isActive } = useStepperItem()

  if (!isActive) {
    return null
  }

  return (
    <div
      data-slot="stepper-content"
      data-state={isActive ? "active" : "inactive"}
      className={cn("mt-4 text-sm", className)}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  useStepper,
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperIndicator,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}

