      data-state={isActive ? "active" : "inactive"}
      className={cn("mt-4 text-sm", className)}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  useStepper,
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperIndicator,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}

